// Generated by GitHub Copilot
export interface BenchmarkCase {
    question: string;
    reference_answer: string;
    retrieved_ids: string[];
    relevant_ids: string[];
    generated_answer: string;
    retrieval_latency_ms: number;
    generation_latency_ms: number;
}

export interface BenchmarkPayload {
    name: string;
    retriever: string;
    generator: string;
    k: number;
    cases: BenchmarkCase[];
}

export interface BenchmarkRunSummary {
    run_id: string;
    created_at: string;
    name: string;
    retriever: string;
    generator: string;
    k: number;
    case_count: number;
    mrr: number;
    recall_at_k: number;
    avg_judge_score: number;
    avg_latency_ms: number;
    p95_latency_ms: number;
}

export interface BenchmarkRunDetail extends BenchmarkRunSummary {
    case_reports: Array<{
        index: number;
        question: string;
        mrr: number;
        recall_at_k: number;
        judge_score: number;
        latency_ms: number;
    }>;
}

const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || "http://localhost:8081";

// Generated by GitHub Copilot
/** Run a benchmark payload and return computed metrics. */
export async function runBenchmark(payload: BenchmarkPayload): Promise<BenchmarkRunDetail> {
    const response = await fetch(`${API_BASE_URL}/api/v1/benchmarks/run`, {
        method: "POST",
        headers: {
            "Content-Type": "application/json"
        },
        body: JSON.stringify(payload)
    });

    if (!response.ok) {
        const error = await response.json().catch(() => ({ error: "request_failed" }));
        throw new Error(error.message || error.error || "Benchmark run failed");
    }

    return response.json() as Promise<BenchmarkRunDetail>;
}

// Generated by GitHub Copilot
/** Fetch benchmark history summaries for leaderboard-style comparison. */
export async function fetchRuns(): Promise<BenchmarkRunSummary[]> {
    const response = await fetch(`${API_BASE_URL}/api/v1/benchmarks/runs`);
    if (!response.ok) {
        throw new Error("Unable to fetch runs");
    }

    const payload = (await response.json()) as { runs: BenchmarkRunSummary[] };
    return payload.runs;
}
